-- Lote 2: Maria, Comunhão dos Santos, Escritura e Tradição
INSERT INTO ai_knowledge_base (category, topic, core_teaching, bible_references, summary, keywords) VALUES

('Doutrina Católica', 'Maria - Theotókos (Mãe de Deus)',
'Maria é Mãe de Deus (Theotókos) porque Jesus é Deus. Ela é mãe da Pessoa de Jesus — o Filho eterno de Deus que assumiu natureza humana. Mãe é mãe de pessoa, não de natureza. Isso não significa que Maria é mãe do Pai ou da Trindade, mas do Filho na sua Pessoa divina. Isabel, cheia do Espírito Santo, a chamou "Mãe do meu Senhor" (Lc 1:43) — Kyrios é nome divino na Septuaginta. O Concílio de Éfeso (431) definiu Theotókos para proteger a cristologia: se Maria não é Mãe de Deus, o que nasceu dela não seria Deus, dividindo Jesus em duas pessoas. O título protege quem é Jesus, não exagera Maria. Na cultura davídica, a mãe do rei era a rainha (Gebirá) — intercessora e honrada, subordinada ao Rei (1Rs 2:19). Maria é a Rainha-Mãe do Reino de Cristo. A Igreja distingue: latria (adoração) só a Deus, dulia (veneração) aos santos, hyperdulia a Maria. Tudo nela aponta para Cristo: "Fazei tudo o que Ele vos disser" (Jo 2:5).',
ARRAY['Lc 1:43','Gl 4:4','Jo 1:14','Mt 1:23','Lc 1:28','Jo 19:26-27','Ap 12:1','Jo 2:5','Lc 1:48','1Rs 2:19'],
'Maria é Theotókos (Mãe de Deus) porque Jesus é Deus e nasceu dela. O título protege a identidade divina de Cristo. Honrar Maria é afirmar a divindade de Jesus.',
ARRAY['maria','theotókos','mãe de deus','rainha-mãe','hyperdulia','veneração','intercessão','cristologia']),

('Doutrina Católica', 'Comunhão dos Santos',
'A comunhão dos santos é a união viva entre todos os membros do Corpo de Cristo — na terra (militante), no céu (triunfante) e no purgatório (padecente). Os santos no céu estão vivos em Deus (Lc 20:38), conscientes de nós e intercedendo. Hebreus 12:1 fala de uma nuvem de testemunhas acompanhando nossa caminhada. Apocalipse 5:8 mostra anciãos no céu oferecendo a Deus as orações dos santos da terra. Se posso pedir oração a um irmão vivo na terra, e os santos no céu estão mais vivos e mais próximos de Deus, é lógico pedir que orem por mim. Pedir intercessão não substitui Jesus — toda intercessão é feita em Cristo e por Cristo. A mediação de Cristo é única (1Tm 2:5); a intercessão dos santos é participação subordinada, como quando pedimos oração a amigos. Não é espiritismo: espiritismo invoca mortos para revelações fora de Deus; intercessão pede oração a quem está com Deus.',
ARRAY['Hb 12:1','Ap 5:8','Ap 8:3-4','Lc 20:38','1Tm 2:1','1Tm 2:5','Lc 15:7','Mt 17:3','2Mc 15:12-16','Rm 15:30'],
'Comunhão dos santos: união viva entre membros do Corpo de Cristo na terra, céu e purgatório. Os santos intercedem por nós em Cristo.',
ARRAY['comunhão dos santos','intercessão','santos','céu','purgatório','corpo de cristo','oração']),

('Escritura e Tradição', 'Tradição Apostólica e Escritura',
'A fé cristã nasceu sustentada por duas colunas inseparáveis: Escritura e Tradição Apostólica. Ambas são Palavra de Deus com mesma autoridade. Paulo ordena: "Guardai as tradições que vos foram ensinadas, seja por palavra, seja por carta" (2Ts 2:15). Nem tudo foi escrito (Jo 21:25). Os cristãos do século I viviam a fé com base na pregação dos apóstolos e na liturgia — o NT como conhecemos só foi definido nos Concílios de Hipona (393) e Cartago (397), mais de 350 anos após Cristo. Até lá, a Tradição Apostólica era a referência segura. Menos de 10% da população sabia ler no século I. O cânon bíblico, o culto dominical, a Trindade como termo — são exemplos de verdades guardadas pela Tradição. A Palavra de Deus é única mas chega por dois modos: Sagrada Escritura (registro inspirado) e Sagrada Tradição (transmissão viva). Negar a Tradição é mutilar a Palavra.',
ARRAY['2Ts 2:15','1Cor 11:2','At 2:42','Jo 21:25','2Tm 1:13-14','At 20:35'],
'Escritura e Tradição são inseparáveis: ambas são Palavra de Deus. A Tradição Apostólica transmite oralmente o que nem tudo coube em livros.',
ARRAY['tradição apostólica','escritura','sola scriptura','bíblia','palavra de deus','cânon','transmissão oral']),

('Escritura e Tradição', 'A Bíblia é Palavra de Deus',
'A Igreja Católica sempre guardou, venerou e proclamou a Escritura como Palavra inspirada e infalível. Toda Escritura é "theopneustos" — soprada por Deus (2Tm 3:16). A Palavra é viva e eficaz (Hb 4:12), lâmpada para os pés (Sl 119:105). Porém, a Palavra escrita nunca foi pensada para andar sozinha. Ela nasceu dentro da Igreja, foi guardada pela Igreja e é interpretada pela Igreja. A Bíblia e a Tradição caminham juntas desde o início. Nos tempos apostólicos não existia Bíblia encadernada — usavam rolos do AT e cartas que circulavam entre comunidades. A Tradição oral era fundamental.',
ARRAY['2Tm 3:16','Hb 4:12','Sl 119:105','Jo 21:25','2Ts 2:15','1Cor 11:2'],
'A Bíblia é Palavra de Deus inspirada e viva, guardada e interpretada pela Igreja. Nasceu dentro da comunidade de fé e caminha com a Tradição.',
ARRAY['bíblia','palavra de deus','inspiração','escritura','tradição','igreja','interpretação']);
